class Solution:
    def solveEquation(self, equation: str) -> str:
        def parse(expr):
            coeff = 0
            const = 0
            i = 0
            n = len(expr)
            sign = 1
            while i < n:
                if expr[i] in '+-':
                    sign = 1 if expr[i] == '+' else -1
                    i += 1
                num = 0
                has_digit = False
                while i < n and expr[i].isdigit():
                    num = num * 10 + int(expr[i])
                    i += 1
                    has_digit = True
                if i < n and expr[i] == 'x':
                    if has_digit:
                        coeff += sign * num
                    else:
                        coeff += sign * 1
                    i += 1
                else:
                    if has_digit:
                        const += sign * num
            return coeff, const

        left, right = equation.split('=', 1)
        a1, b1 = parse(left)
        a2, b2 = parse(right)
        a = a1 - a2
        b = b2 - b1
        if a == 0:
            return "Infinite solutions" if b == 0 else "No solution"
        return f"x={b // a}"

